import{_ as d,o as r,c as a,ag as o}from"./chunks/framework.CQYuu_FX.js";const P=JSON.parse('{"title":"はじめに","description":"","frontmatter":{"title":"はじめに"},"headers":[],"relativePath":"tenant/01-introduction.md","filePath":"tenant/01-introduction.md"}'),i={name:"tenant/01-introduction.md"};function e(l,t,n,h,s,c){return r(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="_1-はじめに" tabindex="-1">1. はじめに <a class="header-anchor" href="#_1-はじめに" aria-label="Permalink to &quot;1. はじめに&quot;">​</a></h1><p>POSLAは、飲食店の注文受付、キッチン連携、会計、スタッフ管理、レポート確認をまとめて行うクラウド型システムです。お客様はテーブルのQRコードから注文し、店舗スタッフは管理画面、ハンディ、KDS、レジ画面を使って営業を進めます。</p><h2 id="poslaでできること" tabindex="-1">POSLAでできること <a class="header-anchor" href="#poslaでできること" aria-label="Permalink to &quot;POSLAでできること&quot;">​</a></h2><ul><li>セルフオーダー、ハンディPOS、テイクアウト、予約の受付</li><li>KDSによる厨房への注文共有</li><li>POSレジでの会計、領収書、返金対応</li><li>メニュー、テーブル、フロアマップ、在庫、シフトの管理</li><li>売上、回転率、スタッフ評価、ABC分析などのレポート確認</li><li>AIアシスタントによる投稿文作成、売上分析、需要予測</li></ul><h2 id="推奨環境" tabindex="-1">推奨環境 <a class="header-anchor" href="#推奨環境" aria-label="Permalink to &quot;推奨環境&quot;">​</a></h2><p>POSLAの店舗業務端末（KDS・レジ・ハンディ）は、<strong>Android端末のGoogle Chrome最新版</strong> でのご利用を <strong>標準環境</strong> としています。管理画面はPCまたはAndroid端末のChrome/Edgeで快適に操作できます。</p><table tabindex="0"><thead><tr><th>用途</th><th>標準環境</th><th>推奨環境</th><th>サポート対象外</th></tr></thead><tbody><tr><td>管理画面</td><td>PC + Chrome最新版</td><td>PC + Edge最新版 / Androidタブレット + Chrome</td><td>Internet Explorer・古いブラウザ</td></tr><tr><td>KDS</td><td>Androidタブレット（10インチ以上）+ Chrome最新版</td><td>—</td><td>iPad/Safari、Fireタブレット、独自ブラウザ</td></tr><tr><td>POSレジ</td><td>Androidタブレット + Chrome最新版</td><td>PC + Chrome最新版</td><td>iPad/Safari、Fireタブレット</td></tr><tr><td>ハンディPOS</td><td>Androidスマホ/タブレット + Chrome最新版</td><td>—</td><td>iPhone/Safari、Fireタブレット</td></tr><tr><td>お客様のセルフオーダー</td><td>お客様のスマートフォン（iPhone/Android問わず）</td><td>主要ブラウザ全般（Safari/Chrome等）</td><td>—</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">顧客セルフメニューはブラウザ自由</p><p>お客様がQRから利用するセルフメニュー、予約、テイクアウト画面はブラウザを限定しません。お手持ちのスマートフォンでそのままご利用いただけます。</p></div><div class="warning custom-block"><p class="custom-block-title">業務端末でiPad/Safariを使う場合の制限</p><p>iPad/Safariでも一部画面は表示できますが、KDSの音声コマンドや通知音、PWAインストール導線は安定して動作しません。安定運用を希望される場合はAndroid端末のChrome最新版をご利用ください。</p></div><p>店舗のWi-Fiが不安定な場合、注文送信や画面更新が遅れることがあります。</p><h2 id="スタッフ端末をホーム画面アプリとして設置する-pwa" tabindex="-1">スタッフ端末をホーム画面アプリとして設置する（PWA） <a class="header-anchor" href="#スタッフ端末をホーム画面アプリとして設置する-pwa" aria-label="Permalink to &quot;スタッフ端末をホーム画面アプリとして設置する（PWA）&quot;">​</a></h2><p>POSLAの<strong>管理画面 / ハンディ / KDS / POSレジ</strong>は、スマホやタブレットの<strong>ホーム画面にアイコンを追加して、1タップでアプリのように起動</strong>できます（PWA: Progressive Web App）。ブラウザのタブやアドレスバーが消え、業務に集中しやすくなります。</p><div class="tip custom-block"><p class="custom-block-title">対象は業務端末のみ</p><p>ホーム画面追加の案内は <strong>管理画面・ハンディ・KDS・POSレジ</strong> で表示されます。お客様がQRから使うセルフメニュー／予約／テイクアウト画面はその都度ブラウザで開く想定なので、PWA化していません（意図的な設計）。</p></div><h3 id="android-標準環境・google-chrome" tabindex="-1">Android（標準環境・Google Chrome） <a class="header-anchor" href="#android-標準環境・google-chrome" aria-label="Permalink to &quot;Android（標準環境・Google Chrome）&quot;">​</a></h3><ol><li>スタッフ端末のChromeで対象画面（管理画面・ハンディ・KDS・POSレジのいずれか）にログインする。</li><li>画面下部に <strong>「📱 POSLAをホーム画面に追加して1タップで起動できます。インストールしますか？」</strong> というバナーが自動で表示される。</li><li><strong>［インストール］</strong> を押すとホーム画面にアイコンが追加される。</li><li>以降はホーム画面のアイコンから直接起動できる（ブラウザのタブ・アドレスバーは非表示）。</li></ol><p>バナーが出ない場合：Chromeのメニュー（右上︙）→「<strong>ホーム画面に追加</strong>」または「<strong>アプリをインストール</strong>」から手動で追加できます。</p><h3 id="iphone-ipad-safari・サポート対象外" tabindex="-1">iPhone / iPad（Safari・サポート対象外） <a class="header-anchor" href="#iphone-ipad-safari・サポート対象外" aria-label="Permalink to &quot;iPhone / iPad（Safari・サポート対象外）&quot;">​</a></h3><p>iPhone / iPad の Safari では、自動のインストール案内が表示されないことがあります。その場合は、以下の手順で手動追加してください。</p><ol><li>Safariで対象画面を開いてログインする。</li><li>画面下の**共有ボタン（□に↑の四角いアイコン）**をタップ。</li><li>メニューから <strong>「ホーム画面に追加」</strong> を選ぶ。</li><li>タイトルを確認して <strong>「追加」</strong> をタップ。</li></ol><div class="warning custom-block"><p class="custom-block-title">iPhone / iPad は業務端末としてはサポート対象外</p><p>ホーム画面追加自体は可能ですが、KDSの音声コマンド・通知音・自動インストールバナーなど一部機能が安定しません。<strong>業務端末はAndroid＋Chromeのご利用を強く推奨</strong>します（お客様側のセルフメニューはiPhone Safariでも問題なくご利用いただけます）。</p></div><h3 id="アイコンを消したいとき" tabindex="-1">アイコンを消したいとき <a class="header-anchor" href="#アイコンを消したいとき" aria-label="Permalink to &quot;アイコンを消したいとき&quot;">​</a></h3><p>ホーム画面のPOSLAアイコンを長押し → 削除（iOS：「ブックマークを削除」／Android：「アンインストール」相当の表示）で外せます。再度追加したい場合は、ブラウザで対象URLを開き直してから上記手順をやり直してください。</p><p>詳しい設定や不明点がある場合は、POSLAサポートへお問い合わせください。</p><h2 id="スタッフ端末で受け取れる通知" tabindex="-1">スタッフ端末で受け取れる通知 <a class="header-anchor" href="#スタッフ端末で受け取れる通知" aria-label="Permalink to &quot;スタッフ端末で受け取れる通知&quot;">​</a></h2><p>ホーム画面に追加したPOSLA（管理画面・ハンディ・KDS・POSレジ）は、<strong>画面を閉じていても業務通知を受け取れます</strong>（Web Push / Android Chrome は全面対応）。</p><h3 id="受け取れる通知-5種類" tabindex="-1">受け取れる通知（5種類） <a class="header-anchor" href="#受け取れる通知-5種類" aria-label="Permalink to &quot;受け取れる通知（5種類）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>#</th><th>通知</th><th>届くタイミング</th><th>届く相手</th><th>タップで開く画面</th></tr></thead><tbody><tr><td>1</td><td><strong>お客様呼び出し</strong></td><td>お客様がセルフメニューの呼び出しボタンを押したとき</td><td>店舗の全端末</td><td>ハンディ画面</td></tr><tr><td>2</td><td><strong>キッチンから呼び出し</strong></td><td>KDSから「提供お願いします」等の呼び出しが入ったとき</td><td>店舗の全端末</td><td>ハンディ画面</td></tr><tr><td>3</td><td><strong>低評価アラート</strong></td><td>お客様の満足度評価が★2以下で送信されたとき</td><td>マネージャー／オーナー</td><td>管理画面ダッシュボード</td></tr><tr><td>4</td><td><strong>重要エラー通知</strong></td><td>監視エージェントが障害や異常を検知したとき</td><td>マネージャー／オーナー</td><td>管理画面ダッシュボード</td></tr><tr><td>5</td><td><strong>テスト送信</strong></td><td>POSLA管理画面「PWA / Push」タブの「テスト送信」から</td><td>自分または店舗全員</td><td>指定した画面</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">通知タップでアプリが自動で開きます</p><p>ホーム画面アイコン経由でPOSLAを開いていた場合、通知をタップすると対応する画面（ハンディ／管理画面など）が直接立ち上がります。ブラウザのタブを毎回開き直す手間がなくなります。</p></div><h3 id="通知を有効にする手順" tabindex="-1">通知を有効にする手順 <a class="header-anchor" href="#通知を有効にする手順" aria-label="Permalink to &quot;通知を有効にする手順&quot;">​</a></h3><ol><li>スタッフ端末でPOSLA（管理画面・ハンディ・KDS・POSレジのいずれか）にログイン。</li><li>初回ログイン時、<strong>「通知を許可しますか？」</strong> のブラウザダイアログが表示されます。</li><li><strong>「許可」</strong> を選ぶと、そのアカウント＋端末の組み合わせが通知購読リストに登録されます。</li><li>ホーム画面にアプリを追加していれば、画面を閉じてもロック画面に通知が表示されます。</li></ol><p>「ブロック」を選んでしまった場合は、Chromeの「設定 → サイトの設定 → 通知」から該当URLを「許可」に戻してください。</p><h3 id="通知が届かないときの確認" tabindex="-1">通知が届かないときの確認 <a class="header-anchor" href="#通知が届かないときの確認" aria-label="Permalink to &quot;通知が届かないときの確認&quot;">​</a></h3><table tabindex="0"><thead><tr><th>症状</th><th>原因 / 対処</th></tr></thead><tbody><tr><td>通知が全く届かない</td><td>ブラウザで通知がブロックされている。Chrome「設定 → 通知」を確認</td></tr><tr><td>Android Chrome で届くが iPhone Safari で届かない</td><td><strong>iOSのWeb Push は対応条件が厳しい</strong>（ホーム画面追加後 + iOS 16.4以降）。業務端末はAndroid推奨</td></tr><tr><td>ハンディにだけ届かない</td><td>該当端末で一度ログアウト → 再ログイン（購読が期限切れの可能性）</td></tr><tr><td>マネージャー画面に低評価通知が来ない</td><td>ログイン中のユーザーのロールが <code>manager</code> / <code>owner</code> になっているか確認</td></tr><tr><td>何度も同じ通知が鳴り続ける</td><td>端末の通知設定でPOSLA通知の「バナー重複」をオフに</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">通知の内容には個人情報を含めません</p><p>通知本文には「テーブル番号」「商品名」「評価点」などの業務情報のみが含まれます。クレジットカード情報・お客様の氏名・電話番号は通知payloadに一切載せません（Web Push の盗聴対策）。</p></div><p>通知設定で迷った場合は、POSLAサポートへお問い合わせください。</p><h2 id="音と通知の仕組み-ポーリング音-と-pwa通知-の組み合わせ" tabindex="-1">音と通知の仕組み（ポーリング音 と PWA通知 の組み合わせ） <a class="header-anchor" href="#音と通知の仕組み-ポーリング音-と-pwa通知-の組み合わせ" aria-label="Permalink to &quot;音と通知の仕組み（ポーリング音 と PWA通知 の組み合わせ）&quot;">​</a></h2><p>POSLAの業務端末では、<strong>新規イベント（注文・呼び出し・低評価など）を気付かせる仕組みが2系統</strong>動いています。両者は独立しており、状況に応じてどちらか、または両方が作動します。</p><h3 id="_2つの系統" tabindex="-1">2つの系統 <a class="header-anchor" href="#_2つの系統" aria-label="Permalink to &quot;2つの系統&quot;">​</a></h3><p><strong>系統A: 画面を開いているときの「アプリ内ポーリング + 音」</strong> 画面が開いている間、POSLAはサーバーへ定期的に問い合わせて新着を取りに行きます。新着があれば<strong>画面内のチャイム音＋視覚アラート＋バイブ</strong>でスタッフに気付かせます。<strong>PWA導入なしでもブラウザだけで動作</strong>します。</p><table tabindex="0"><thead><tr><th>画面</th><th>ポーリング間隔</th><th>検知対象</th></tr></thead><tbody><tr><td>KDS（注文一覧）</td><td>約2秒</td><td>新規注文、ステータス変更</td></tr><tr><td>KDS / ハンディ（呼び出しアラート）</td><td>約5秒</td><td>スタッフ呼び出し</td></tr><tr><td>POSレジ（注文ポーリング）</td><td>約5秒</td><td>会計対象の新規注文</td></tr><tr><td>ハンディ（テーブル状態）</td><td>約5秒</td><td>テーブル着席・会計状況</td></tr><tr><td>売上サマリー・品切れ情報</td><td>約30秒</td><td>集計更新</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">初回の音出し許可（ハンディ）</p><p>ハンディ端末はモバイルブラウザの自動再生規制があるため、<strong>起動直後に画面を1回タップ</strong>してAudioContextを解放する必要があります。「タップして音声を有効化」バナーが出たら、画面のどこかを1回タップしてください。一度有効化すれば、その画面セッション中は以後のイベントで自動的に鳴ります。</p></div><p><strong>系統B: PWA導入 ＋ 通知許可による「OS通知（Web Push）」</strong> ホーム画面追加＋通知許可をセットで設定すると、<strong>画面やアプリを閉じていても</strong>OSのロック画面・通知センターに通知が届きます。前節「スタッフ端末で受け取れる通知」の5種類がこれに該当します。</p><h3 id="両方が動くときの動作-4パターン" tabindex="-1">両方が動くときの動作（4パターン） <a class="header-anchor" href="#両方が動くときの動作-4パターン" aria-label="Permalink to &quot;両方が動くときの動作（4パターン）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>画面の状態</th><th>通知許可</th><th>届き方</th><th>備考</th></tr></thead><tbody><tr><td>画面を開いている</td><td>許可あり</td><td><strong>系統A の画面内音</strong> + <strong>系統B のOS通知</strong> の<strong>両方</strong>が動く</td><td>見逃し防止には有効。「音が二重」と感じる場合は下記の対処を参照</td></tr><tr><td>画面を開いている</td><td>許可なし</td><td>系統A の画面内音のみ</td><td>PWA導入前と同じ挙動。最小構成</td></tr><tr><td>画面を閉じている／別アプリ中</td><td>許可あり</td><td>系統B のOS通知のみ</td><td>ポーリングは止まっているため画面内音は鳴らない。画面を開き直すと未対応イベントがまとめて表示される</td></tr><tr><td>画面を閉じている／別アプリ中</td><td>許可なし</td><td>何も届かない</td><td>次にPOSLAを開いたときに溜まったイベントを確認する運用になる</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">Android Chrome は画面を開いていてもOS通知が出ます</p><p>Android Chromeの仕様で、PWAがフォアグラウンド（画面を見ている状態）でもWeb Push通知はOS通知として表示されます。そのため上記「画面を開いている + 許可あり」では系統Aのアプリ内音と系統BのOS通知が<strong>実質同時に発火</strong>することがあります。POSLA側では自動的な重複排除は行っていません（見逃し防止を優先）。</p></div><h3 id="「音が二重に鳴るのが気になる」場合" tabindex="-1">「音が二重に鳴るのが気になる」場合 <a class="header-anchor" href="#「音が二重に鳴るのが気になる」場合" aria-label="Permalink to &quot;「音が二重に鳴るのが気になる」場合&quot;">​</a></h3><table tabindex="0"><thead><tr><th>対処</th><th>方法</th><th>影響</th></tr></thead><tbody><tr><td>A: OS通知の音だけ無音にする</td><td>Android「設定 → 通知 → POSLA → サウンド: なし」（バッジとバナーは残す）</td><td>画面内音のみ鳴る。画面を閉じた時は静かなバナーだけ届く</td></tr><tr><td>B: PWA側の通知許可を切る</td><td>Chrome「設定 → サイトの設定 → 通知 → POSLAのURL: ブロック」</td><td>画面を開いている間だけ音が鳴る（PWA導入前と同じ状態に戻す）</td></tr><tr><td>C: 業務端末では両方オン</td><td>（標準推奨）</td><td>画面を開いていれば両方、閉じていればOS通知のみ。見逃しが一番少ない</td></tr></tbody></table><h3 id="pwaを導入すると何が増えるか-通知以外" tabindex="-1">PWAを導入すると何が増えるか（通知以外） <a class="header-anchor" href="#pwaを導入すると何が増えるか-通知以外" aria-label="Permalink to &quot;PWAを導入すると何が増えるか（通知以外）&quot;">​</a></h3><ul><li><strong>ホーム画面アイコンから1タップ起動</strong>：ブラウザのタブを探さずに済む</li><li><strong>OS通知（画面を閉じていても届く）</strong>：前節の5種類</li><li><strong>アプリバッジ</strong>：ホーム画面アイコンに未対応件数の赤い丸数字（KDS・ハンディの呼び出し件数に連動、Android対応ブラウザのみ）</li><li><strong>全画面表示</strong>：ブラウザのアドレスバー・タブが消え、業務情報の表示領域が広がる</li><li><strong>起動が少し速い</strong>：ブラウザ分のUIを省けるため</li></ul><p>オフライン機能（通信が切れても直近の画面を表示し続ける）は段階的に拡張中です。現在は<strong>KDSと緊急レジが限定的に対応</strong>しています（詳細は Part 8: トラブルシューティング）。</p><h2 id="ロールの違い" tabindex="-1">ロールの違い <a class="header-anchor" href="#ロールの違い" aria-label="Permalink to &quot;ロールの違い&quot;">​</a></h2><table tabindex="0"><thead><tr><th>ロール</th><th>主な利用者</th><th>できること</th></tr></thead><tbody><tr><td>オーナー</td><td>経営者・本部担当者</td><td>全店舗の管理、ユーザー管理、複数店舗レポート、契約・決済設定</td></tr><tr><td>マネージャー</td><td>店長・責任者</td><td>担当店舗のメニュー、注文、会計、在庫、シフト、レポート管理</td></tr><tr><td>スタッフ</td><td>ホール・キッチン担当</td><td>勤怠打刻、シフト確認、希望シフト提出など</td></tr><tr><td>端末専用アカウント</td><td>KDS・レジ・ハンディ端末</td><td>店舗備品端末での業務利用</td></tr></tbody></table><p>POSLAでは、全スタッフに個別アカウントを作成してください。共有アカウントを使うと、勤怠、監査ログ、スタッフ評価で「誰が操作したか」を正しく記録できません。</p><h2 id="ご契約プラン" tabindex="-1">ご契約プラン <a class="header-anchor" href="#ご契約プラン" aria-label="Permalink to &quot;ご契約プラン&quot;">​</a></h2><p>POSLA は <strong>単一プラン + 任意アドオン</strong> の構成です。すべての機能（セルフオーダー、ハンディPOS、KDS、POSレジ、テイクアウト、予約、在庫、シフト、AIアシスタント、多言語、レポート、決済連携など）はすべての契約者に標準提供されます。</p><table tabindex="0"><thead><tr><th>項目</th><th>月額</th></tr></thead><tbody><tr><td>基本料金（1店舗目）</td><td>¥20,000</td></tr><tr><td>追加店舗（2店舗目以降）</td><td>¥17,000 / 店舗（15%引き）</td></tr><tr><td>本部一括メニュー配信アドオン（任意）</td><td>+¥3,000 / 店舗</td></tr></tbody></table><p><strong>お試し利用：</strong> 初回ご契約から <strong>30日間無料</strong>。期間中に解約された場合は課金されません。31日目から自動で月額課金が開始されます（カード登録は契約時に必要）。</p><p>ご契約内容の確認・店舗追加・アドオンのオンオフは、オーナーダッシュボードの「契約・お支払い」から操作できます。詳しい手順は <a href="/docs-tenant/operations/part7-billing.html">Part 7: 契約・お支払い</a> をご覧ください。</p><h2 id="導入時の基本順序" tabindex="-1">導入時の基本順序 <a class="header-anchor" href="#導入時の基本順序" aria-label="Permalink to &quot;導入時の基本順序&quot;">​</a></h2><ol><li>オーナーアカウントでログインします。</li><li>店舗情報、営業時間、税率、支払い方法を設定します。</li><li>スタッフアカウントと端末専用アカウントを作成します。</li><li>メニュー、テーブル、フロアマップを登録します。</li><li>KDS、レジ、プリンタ、決済端末を確認します。</li><li>テスト注文とテスト会計を行います。</li><li>問題がなければ、お客様用QRコードを掲示します。</li></ol><h2 id="困ったとき" tabindex="-1">困ったとき <a class="header-anchor" href="#困ったとき" aria-label="Permalink to &quot;困ったとき&quot;">​</a></h2><p>まずは画面に表示されたメッセージ、操作した画面名、発生時刻を控えてください。管理画面右下の <strong>「📚 サポートガイド」</strong> から FAQ / 症状別の案内 / エラー番号検索を利用できます。解決しない場合は POSLAサポートへご連絡ください。上記の情報を添えていただくと確認がスムーズです。</p>',62)])])}const b=d(i,[["render",e]]);export{P as __pageData,b as default};
